-- WHERE patient_key = 'P23'
-- ORDER BY year_month_key;
-- ============================================================================-- ============================================================================
-- PREDIABETES (PREDIAB) — REPORT VIEWS
-- ============================================================================
-- Creates 2 standard Module-1 report views (mirror of the DM/HTN/DLP/OB pattern):
--   1. rpt_prediab_prevalence_annual     — Report 2 (standard annual prevalence)
--   2. rpt_prediab_incidence_monthly     — Report 3 (standard monthly incidence)
--
-- The PREDIAB-specific HIGH-RISK PATIENTS report has been moved to the GENERIC
-- module-2 file 00a_high_risk_views.sql as rpt_high_risk_patients_annual. It is
-- parameterized by condition via chi_high_risk_factors; for v1 only PREDIAB has
-- factors defined.
--
-- Each report emits rows with a `sort_order` column:
--   • sort_order=0 — detail rows (per cluster / per cluster × month)
--   • sort_order=1 — cluster subtotals (only for monthly reports)
--   • sort_order=2 — grand total ('-- ALL CLUSTERS --')
--
-- Prerequisites:
--   1. Run all Prediabetes staging + analytical views first
-- ============================================================================


-- ############################################################################
-- REPORT 3: rpt_prediab_incidence_monthly
-- ############################################################################
-- Reports the rate of NEW prediabetes (R73.03) diagnoses per 100,000
-- at-risk population per month, by health cluster.
--
-- Denominator: patients at-risk at start of month = no prior R73.03 diagnosis
-- Numerator:   patients who received first-ever R73.03 this month
-- Rate:        per 100,000 at-risk population
--
-- Direct mirror of rpt_dm_incidence_monthly (3-layer UNION ALL).
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.rpt_prediab_incidence_monthly AS

WITH incidence_metrics AS (
    SELECT
        health_cluster,
        report_year,
        report_month,
        year_month_key,
        COUNT(DISTINCT CASE WHEN is_prediab_at_risk_start = TRUE
                        THEN patient_key END)   AS at_risk_population_start,
        COUNT(DISTINCT CASE WHEN is_prediab_incident_case = TRUE
                        THEN patient_key END)   AS incident_cases,
        ROUND(incident_cases / NULLIF(at_risk_population_start, 0) * 100000, 2)
                                                AS incidence_rate_per_100k
    FROM CHI_REPORTING.stg_prediab_patient_month
    GROUP BY health_cluster, report_year, report_month, year_month_key
)

-- Monthly detail rows (sort_order=0)
SELECT
    report_year                              AS year,
    health_cluster,
    TO_VARCHAR(
        TO_DATE(year_month_key::VARCHAR || '01', 'YYYYMMDD'),
        'MON YYYY'
    )                                        AS period,
    at_risk_population_start,
    incident_cases,
    incidence_rate_per_100k,
    year_month_key                           AS sort_key,
    0                                        AS sort_order
FROM incidence_metrics

UNION ALL

-- Cluster subtotal rows (sort_order=1)
-- Annual rate = total cases / January at-risk × 100,000
SELECT
    report_year                              AS year,
    health_cluster,
    '── ' || health_cluster || ' TOTAL ──'  AS period,
    NULL                                     AS at_risk_population_start,
    SUM(incident_cases)                      AS incident_cases,
    ROUND(SUM(incident_cases) / NULLIF(
        MAX(CASE WHEN report_month = 1 THEN at_risk_population_start END), 0
    ) * 100000, 2)                           AS incidence_rate_per_100k,
    99999                                    AS sort_key,
    1                                        AS sort_order
FROM incidence_metrics
GROUP BY health_cluster, report_year

UNION ALL

-- Grand total row — all clusters combined (sort_order=2)
-- Annual rate = total cases / total January at-risk × 100,000
SELECT
    report_year                              AS year,
    '── ALL CLUSTERS ──'                    AS health_cluster,
    '── ' || report_year || ' ALL CLUSTERS ──' AS period,
    NULL                                     AS at_risk_population_start,
    SUM(incident_cases)                      AS incident_cases,
    ROUND(SUM(incident_cases) / NULLIF(
        SUM(CASE WHEN report_month = 1 THEN at_risk_population_start END), 0
    ) * 100000, 2)                           AS incidence_rate_per_100k,
    99999                                    AS sort_key,
    2                                        AS sort_order
FROM incidence_metrics
GROUP BY report_year

ORDER BY health_cluster, sort_order, sort_key;


-- ############################################################################
-- REPORT 2: rpt_prediab_prevalence_annual
-- ############################################################################
-- Standard Module-1 prevalence report for prediabetes (R73.03).
-- Reports the % of the eligible population diagnosed with prediabetes by year-end.
--
-- Denominator: total eligible population (is_in_total_population = TRUE) at year-end
-- Numerator:   patients with first R73.03 diagnosis before report_end
-- Rate:        prevalent / total × 100
--
-- Direct mirror of rpt_dm_prevalence_annual. Two-layer rows (per-cluster
-- detail + grand total). For prediabetes the target code is R73.03 only
-- (no broader code set like DM's E10/E11/E13/E14/O24), so the "incident during
-- year" sub-count simplifies.
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.rpt_prediab_prevalence_annual AS

WITH prevalence_snapshot AS (
    SELECT
        patient_key,
        first_r73_date,
        CASE WHEN first_r73_date IS NOT NULL
              AND first_r73_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                                     AS has_r73_at_year_end,
        CASE WHEN first_r73_date >= cfg.report_start
              AND first_r73_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                                     AS is_incident_this_year,
        CASE WHEN first_r73_date < cfg.report_start
             THEN TRUE ELSE FALSE
        END                                     AS is_pre_existing
    FROM CHI_REPORTING.stg_prediab_cohort
    CROSS JOIN CHI_REPORTING.chi_config cfg
)

-- Per-cluster rows (sort_order=0)
SELECT
    cfg.report_year                             AS year,
    bc.health_cluster,
    COUNT(DISTINCT CASE WHEN bc.is_in_total_population = TRUE
                    THEN bc.patient_key END)    AS total_population,
    COUNT(DISTINCT CASE WHEN ps.has_r73_at_year_end = TRUE
                    THEN bc.patient_key END)    AS prevalent_prediab_count,
    COUNT(DISTINCT CASE WHEN ps.is_incident_this_year = TRUE
                    THEN bc.patient_key END)    AS incident_during_year,
    COUNT(DISTINCT CASE WHEN ps.is_pre_existing = TRUE
                          AND ps.has_r73_at_year_end = TRUE
                    THEN bc.patient_key END)    AS pre_existing_prediab_count,
    ROUND(prevalent_prediab_count / NULLIF(total_population, 0) * 100, 4)
                                                AS prevalence_rate_pct,
    bc.health_cluster                           AS period_label,
    0                                           AS sort_order
FROM CHI_REPORTING.stg_prediab_cohort bc
CROSS JOIN CHI_REPORTING.chi_config cfg
LEFT JOIN prevalence_snapshot ps USING (patient_key)
GROUP BY cfg.report_year, bc.health_cluster

UNION ALL

-- Grand total row (sort_order=2)
SELECT
    cfg.report_year                             AS year,
    '── ALL CLUSTERS ──'                       AS health_cluster,
    COUNT(DISTINCT CASE WHEN bc.is_in_total_population = TRUE
                    THEN bc.patient_key END)    AS total_population,
    COUNT(DISTINCT CASE WHEN ps.has_r73_at_year_end = TRUE
                    THEN bc.patient_key END)    AS prevalent_prediab_count,
    COUNT(DISTINCT CASE WHEN ps.is_incident_this_year = TRUE
                    THEN bc.patient_key END)    AS incident_during_year,
    COUNT(DISTINCT CASE WHEN ps.is_pre_existing = TRUE
                          AND ps.has_r73_at_year_end = TRUE
                    THEN bc.patient_key END)    AS pre_existing_prediab_count,
    ROUND(COUNT(DISTINCT CASE WHEN ps.has_r73_at_year_end = TRUE THEN bc.patient_key END)
          / NULLIF(COUNT(DISTINCT CASE WHEN bc.is_in_total_population = TRUE THEN bc.patient_key END), 0) * 100, 4)
                                                AS prevalence_rate_pct,
    '── ' || cfg.report_year || ' ALL CLUSTERS ──' AS period_label,
    2                                           AS sort_order
FROM CHI_REPORTING.stg_prediab_cohort bc
CROSS JOIN CHI_REPORTING.chi_config cfg
LEFT JOIN prevalence_snapshot ps USING (patient_key)

ORDER BY health_cluster, sort_order;

-- ============================================================================
-- HIGH-RISK FACTORS CONFIG (extracted from 00_config.sql — appended here to
-- preserve the chi_care_gap_config verify SELECT ordering above)
-- ============================================================================

-- ============================================================================
-- HIGH-RISK FACTORS — Configurable risk-factor definitions by condition
-- ============================================================================
-- Each row defines one risk factor for one condition. The High-Risk Patients
-- report (Module 2, Report 7) reads from this table to identify which
-- patients in a condition's prevalent cohort carry ≥ N weighted risk factors.
--
-- For v1, only PREDIAB is populated (the first condition the High-Risk
-- report is being deployed for). Other conditions return zero rows in the
-- report until their factors are added here — no schema change required.
--
-- Adding factors to a new condition:
--   1. INSERT a new row for each risk factor
--   2. The view auto-detects the new condition and produces output
--   3. No SQL change needed
-- ============================================================================

CREATE TABLE IF NOT EXISTS CHI_REPORTING.chi_high_risk_factors (
    condition        VARCHAR,        -- 'dm', 'htn', 'dlp', 'ob', 'prediab'
    factor_code      VARCHAR,        -- short identifier, e.g. 'bmi_ge_25', 'htn_dx'
    factor_label     VARCHAR,        -- display name for the high-risk report
    source_view      VARCHAR,        -- view/table to LEFT JOIN (e.g. 'CHI_REPORTING.stg_htn_cohort')
    source_column    VARCHAR,        -- boolean column on that view (e.g. 'has_any_htn_diagnosis');
                                    --   use 'always_false' as a sentinel for unimplemented factors
    value_min        DECIMAL(10,2),  -- for value-based factors (e.g. BMI ≥ 25); NULL otherwise
    weight           INTEGER,        -- contribution to risk_factor_count (default 1)
    requires_value   BOOLEAN,        -- TRUE = numeric threshold (BMI); FALSE = boolean flag (dx)
    level_order      INTEGER         -- display order in the report
);

DELETE FROM CHI_REPORTING.chi_high_risk_factors;

-- PREDIAB — first condition, all 6 risk factors
INSERT INTO CHI_REPORTING.chi_high_risk_factors VALUES
('prediab', 'bmi_ge_25',               'BMI ≥ 25 (latest 2025)',         'CHI_REPORTING.stg_prediab_cohort', 'has_bmi_ge_25',            NULL, 1, FALSE, 1),
('prediab', 'htn_dx',                  'Hypertension diagnosis',         'CHI_REPORTING.stg_prediab_cohort', 'has_htn_dx',               NULL, 1, FALSE, 2),
('prediab', 'dlp_dx',                  'Dyslipidemia diagnosis',         'CHI_REPORTING.stg_prediab_cohort', 'has_dlp_dx',               NULL, 1, FALSE, 3),
('prediab', 'family_history_diabetes', 'First-degree family hx of DM',   'chi_high_risk_factors',            'always_false',             NULL, 1, FALSE, 4),
('prediab', 'gdm_history',             'Gestational DM history',         'CHI_REPORTING.stg_prediab_cohort', 'has_gdm_history',          NULL, 1, FALSE, 5),
('prediab', 'pcos_e28_2',              'PCOS / PMOS proxy (E28.2)',     'CHI_REPORTING.stg_prediab_cohort', 'has_pcos',                 NULL, 1, FALSE, 6);

-- Verify
SELECT 'chi_high_risk_factors' AS config_table, COUNT(*) AS rows
FROM CHI_REPORTING.chi_high_risk_factors;

-- ============================================================================
-- HIGH-RISK PATIENTS (GENERIC) — STAGING VIEW
-- ============================================================================
-- Creates 1 generic staging view (stg_high_risk_patient). The per-condition
-- report views (rpt_{cond}_prevalence_high_risk_annual) live in each
-- condition's own folder (see Prediabetes/prediab_high_risk_report.sql for
-- the Prediabetes report, appended after this section).
--
-- For v1, only PREDIAB has factors defined in chi_high_risk_factors. To
-- extend to other conditions: INSERT new rows into chi_high_risk_factors
-- and create a corresponding rpt_{cond}_prevalence_high_risk_annual view
-- in the condition's folder.
--
-- Prerequisites:
--   1. Run 00_config.sql first (creates CHI_REPORTING.chi_config + config
--      tables, including chi_high_risk_factors)
--   2. Run all per-condition staging views (so stg_*_cohort views exist for
--      the risk-factor JOINs)
--   3. Run Prediabetes/prediab_staging_views.sql so the 6 PREDIAB risk-factor
--      flag columns exist on stg_prediab_cohort
-- ============================================================================


-- ############################################################################
-- VIEW: stg_high_risk_patient
-- ############################################################################
-- Grain: one row per (patient, condition) per report year, for all conditions
--        that have ≥1 risk factor defined in chi_high_risk_factors.
--
-- For each (patient, condition, factor) row, evaluates has_factor = TRUE/FALSE
-- by reading the source_view column from the config and checking source_column.
--
-- Output columns:
--   patient_key              — patient identifier
--   condition                — 'dm', 'htn', 'dlp', 'ob', 'prediab'
--   is_prevalent_year_end    — patient is eligible AND has condition at Dec 31
--   risk_factor_count        — sum of has_factor across all factors for (patient, condition)
--   is_high_risk             — risk_factor_count >= MIN_FACTORS_FOR_HIGH_RISK (default 2)
-- ============================================================================

CREATE OR REPLACE VIEW CHI_REPORTING.stg_high_risk_patient AS

WITH total_population AS (
    SELECT
        p._ID                                   AS patient_key,
        CASE WHEN DATEDIFF(YEAR, p.DATEOFBIRTH, cfg.report_start) > 18
              AND p.NATIONALID IS NOT NULL
              AND p.NATIONALID <> ''
              AND (p.DATEOFDEATH IS NULL OR p.DATEOFDEATH >= cfg.report_start)
             THEN TRUE ELSE FALSE
        END                                     AS is_in_total_population
    FROM NMR.LEANHIS.PATIENTS p
    CROSS JOIN CHI_REPORTING.chi_config cfg
    WHERE p.DATEOFBIRTH <= DATEADD(YEAR, -18, cfg.report_start)
),

-- One row per (patient, condition) where the patient is prevalent at year-end.
-- The "is pre X at year-end" check uses the condition's first-relevant-diagnosis
-- date. For v1 we hardcode the condition -> cohort view mapping inline; the
-- generic High-Risk report only needs the (patient, condition, is_prevalent)
-- pair, so a per-condition CASE here is sufficient.
prevalent_per_condition AS (
    SELECT
        tp.patient_key,
        cfg.report_year,
        'prediab'                AS condition,
        CASE WHEN pc.first_r73_date IS NOT NULL
              AND pc.first_r73_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                      AS is_prevalent_year_end,
        pc.is_in_total_population
    FROM total_population tp
    CROSS JOIN CHI_REPORTING.chi_config cfg
    LEFT JOIN CHI_REPORTING.stg_prediab_cohort pc
            ON pc.patient_key = tp.patient_key
    UNION ALL
    SELECT
        tp.patient_key,
        cfg.report_year,
        'dm'                     AS condition,
        CASE WHEN dc.first_e11_date IS NOT NULL
              AND dc.first_e11_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                      AS is_prevalent_year_end,
        dc.is_in_total_population
    FROM total_population tp
    CROSS JOIN CHI_REPORTING.chi_config cfg
    LEFT JOIN CHI_REPORTING.stg_dm_cohort dc
            ON dc.patient_key = tp.patient_key
    UNION ALL
    SELECT
        tp.patient_key,
        cfg.report_year,
        'htn'                    AS condition,
        CASE WHEN hc.first_i10_date IS NOT NULL
              AND hc.first_i10_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                      AS is_prevalent_year_end,
        hc.is_in_total_population
    FROM total_population tp
    CROSS JOIN CHI_REPORTING.chi_config cfg
    LEFT JOIN CHI_REPORTING.stg_htn_cohort hc
            ON hc.patient_key = tp.patient_key
    UNION ALL
    SELECT
        tp.patient_key,
        cfg.report_year,
        'dlp'                    AS condition,
        CASE WHEN lc.first_e78_date IS NOT NULL
              AND lc.first_e78_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                      AS is_prevalent_year_end,
        lc.is_in_total_population
    FROM total_population tp
    CROSS JOIN CHI_REPORTING.chi_config cfg
    LEFT JOIN CHI_REPORTING.stg_dlp_cohort lc
            ON lc.patient_key = tp.patient_key
    UNION ALL
    SELECT
        tp.patient_key,
        cfg.report_year,
        'ob'                     AS condition,
        CASE WHEN oc.first_e66_date IS NOT NULL
              AND oc.first_e66_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                      AS is_prevalent_year_end,
        oc.is_in_total_population
    FROM total_population tp
    CROSS JOIN CHI_REPORTING.chi_config cfg
    LEFT JOIN CHI_REPORTING.stg_ob_cohort oc
            ON oc.patient_key = tp.patient_key
),

-- Only conditions that have at least one risk factor in the config produce
-- output. This is the "extension point" — INSERT a row into chi_high_risk_factors
-- and that condition will start showing up in the report.
conditions_with_factors AS (
    SELECT DISTINCT condition
    FROM CHI_REPORTING.chi_high_risk_factors
),

-- One row per (patient, condition, factor) for evaluation. The source_view
-- and source_column from the config are used to compute has_factor. For the
-- "always_false" sentinel (unimplemented factors), has_factor = FALSE.
factor_evaluations AS (
    SELECT
        ppc.patient_key,
        ppc.condition,
        hrf.factor_code,
        hrf.weight,
        hrf.level_order,
        -- Evaluate the factor against the patient. The CHI_REPORTING.stg_prediab_cohort
        -- case is handled specially because its columns are direct boolean flags
        -- (not nested inside a CTE). Other conditions can be wired the same way
        -- by adding a CASE branch when their cohort view is added.
        CASE
            WHEN hrf.source_column = 'always_false' THEN FALSE
            WHEN hrf.source_view = 'CHI_REPORTING.stg_prediab_cohort'
                 AND hrf.source_column = 'has_bmi_ge_25'        THEN COALESCE((SELECT has_bmi_ge_25          FROM CHI_REPORTING.stg_prediab_cohort WHERE patient_key = ppc.patient_key), FALSE)
            WHEN hrf.source_view = 'CHI_REPORTING.stg_prediab_cohort'
                 AND hrf.source_column = 'has_htn_dx'           THEN COALESCE((SELECT has_htn_dx             FROM CHI_REPORTING.stg_prediab_cohort WHERE patient_key = ppc.patient_key), FALSE)
            WHEN hrf.source_view = 'CHI_REPORTING.stg_prediab_cohort'
                 AND hrf.source_column = 'has_dlp_dx'           THEN COALESCE((SELECT has_dlp_dx             FROM CHI_REPORTING.stg_prediab_cohort WHERE patient_key = ppc.patient_key), FALSE)
            WHEN hrf.source_view = 'CHI_REPORTING.stg_prediab_cohort'
                 AND hrf.source_column = 'has_gdm_history'      THEN COALESCE((SELECT has_gdm_history        FROM CHI_REPORTING.stg_prediab_cohort WHERE patient_key = ppc.patient_key), FALSE)
            WHEN hrf.source_view = 'CHI_REPORTING.stg_prediab_cohort'
                 AND hrf.source_column = 'has_pcos'             THEN COALESCE((SELECT has_pcos               FROM CHI_REPORTING.stg_prediab_cohort WHERE patient_key = ppc.patient_key), FALSE)
            ELSE FALSE
        END                                                         AS has_factor
    FROM prevalent_per_condition ppc
    INNER JOIN conditions_with_factors cwf
            ON cwf.condition = ppc.condition
    CROSS JOIN CHI_REPORTING.chi_high_risk_factors hrf
    WHERE hrf.condition = ppc.condition
      AND ppc.is_prevalent_year_end = TRUE
)

SELECT
    patient_key,
    condition,
    report_year,
    SUM(CASE WHEN has_factor THEN weight ELSE 0 END)             AS risk_factor_count,
    CASE WHEN SUM(CASE WHEN has_factor THEN weight ELSE 0 END) >= 2
         THEN TRUE ELSE FALSE
    END                                                            AS is_high_risk
FROM factor_evaluations
GROUP BY patient_key, condition, report_year;


-- ############################################################################
-- VIEW 2: rpt_high_risk_patients_annual — MOVED
-- ############################################################################
-- The cross-condition aggregator that was previously defined here has been
-- moved. In v1 the report was only producing output for PREDIAB (the only
-- condition with risk factors in chi_high_risk_factors), so it now lives at
-- project_queries/Prediabetes/prediab_high_risk_report.sql as
-- rpt_prediab_prevalence_high_risk_annual (prediabetes-specific).
--
-- When other conditions (DM, HTN, DLP, OB) add risk factors via the config
-- table, the corresponding rpt_{cond}_prevalence_high_risk_annual views
-- will live in their respective condition folders. A cross-condition
-- aggregator can be reintroduced here at that point if needed.
-- ============================================================================


-- ============================================================================
-- PREDIABETES (PREDIAB) — HIGH-RISK PATIENTS REPORT
-- ============================================================================
-- Creates 1 Module-2 report view for prediabetes:
--   1. rpt_prediab_prevalence_high_risk_annual
--
-- Reads from the GENERIC stg_high_risk_patient view (project_queries/00a_high_risk_views.sql),
-- filtering to condition = 'prediab' rows. v1 only emits output for PREDIAB
-- because that is the only condition with risk factors defined in
-- chi_high_risk_factors (see 00_config.sql).
--
-- This file lives in project_queries/Prediabetes/ because the v1 output is
-- prediabetes-specific. When other conditions add risk factors via the
-- config table, the corresponding `rpt_{cond}_prevalence_high_risk_annual`
-- views will live in their respective condition folders; this file's
-- report can be generalized into a cross-condition aggregator at that point
-- (or remain as a thin per-condition wrapper).
--
-- Prerequisites:
--   1. Run 00_config.sql first (creates CHI_REPORTING.chi_config +
--      chi_control_thresholds + chi_care_gap_config + chi_high_risk_factors)
--   2. Run Prediabetes/prediab_staging_views.sql
--   3. Run 00a_high_risk_views.sql (creates the generic stg_high_risk_patient)
-- ============================================================================


-- ############################################################################
-- REPORT: rpt_prediab_prevalence_high_risk_annual
-- ############################################################################
-- Annual Module-2 report: among prediabetes patients (R73.03 by year-end),
-- what % carry ≥2 high-risk factors (BMI ≥25, HTN dx, DLP dx, family-history
-- placeholder, GDM history, PCOS via E28.2)?
--
-- Denominator: Prediabetes-prevalent patients at year-end (R73.03 by Dec 31)
-- Numerator:   subset of those flagged is_high_risk = TRUE by stg_high_risk_patient
-- Rate:        high-risk count / total prediab population × 100
--
-- Two-layer rows (per-cluster detail + grand total). Same shape as
-- rpt_prediab_prevalence_annual; differs in numerator definition
-- (is_high_risk instead of any-prevalent).
-- ============================================================================

CREATE OR REPLACE VIEW CHI_REPORTING.rpt_prediab_prevalence_high_risk_annual AS

WITH snap AS (
    SELECT
        hr.patient_key,
        COALESCE(pc.health_cluster, 'Unassigned')   AS health_cluster,
        hr.is_high_risk
    FROM CHI_REPORTING.stg_high_risk_patient hr
    LEFT JOIN CHI_REPORTING.stg_prediab_cohort pc
            ON pc.patient_key = hr.patient_key
    WHERE hr.condition = 'prediab'
)

-- Detail rows (sort_order=0): per health cluster
SELECT
    2025                                                  AS year,
    health_cluster,
    COUNT(*)                                              AS total_prediab_population,
    SUM(CASE WHEN is_high_risk THEN 1 ELSE 0 END)         AS high_risk_count,
    ROUND(
        SUM(CASE WHEN is_high_risk THEN 1 ELSE 0 END) * 100.0
        / NULLIF(COUNT(*), 0),
        2
    )                                                     AS high_risk_pct,
    health_cluster                                        AS sort_key,
    0                                                     AS sort_order
FROM snap
GROUP BY health_cluster

UNION ALL

-- Grand total row (sort_order=2): all clusters combined
SELECT
    2025                                                  AS year,
    '── ALL CLUSTERS ──'                                AS health_cluster,
    COUNT(*)                                              AS total_prediab_population,
    SUM(CASE WHEN is_high_risk THEN 1 ELSE 0 END)         AS high_risk_count,
    ROUND(
        SUM(CASE WHEN is_high_risk THEN 1 ELSE 0 END) * 100.0
        / NULLIF(COUNT(*), 0),
        2
    )                                                     AS high_risk_pct,
    '── 2025 ALL CLUSTERS ──'                            AS sort_key,
    2                                                     AS sort_order
FROM snap

ORDER BY sort_order, sort_key;
